import React, { useState } from 'react';
import { Bot, Database, CalendarDays, Plus, Trash2, Save, Play, ClipboardPaste, FileSpreadsheet } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : {
      lineMap: { 'T1': 'SEC-T1(USA)', 'P1F': 'SEC-P1(F)(KR)' },
      modelMap: { 'SUPRA-N': { model: 'SUPRA N', pm: 0 } },
      atmMaster: [{ id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 }]
    };
  });

  const saveRules = (newRules) => {
    setMappingRules(newRules);
    localStorage.setItem('pskMasterData', JSON.stringify(newRules));
  };

  const removeAtmRule = (id) => {
    const updated = { ...mappingRules, atmMaster: mappingRules.atmMaster.filter(a => a.id !== id) };
    saveRules(updated);
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans">
      <aside className="w-64 bg-[#1a233a] text-white flex flex-col shadow-xl">
        <div className="h-16 flex items-center px-6 bg-[#111827] font-bold text-xl"><Bot className="mr-2 text-blue-400" /> PSK Portal</div>
        <nav className="flex-1 p-4">
          <button onClick={() => setActiveTab('fcst')} className={`w-full p-3 mb-2 rounded ${activeTab === 'fcst' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}>FCST 스케줄러</button>
          <button onClick={() => setActiveTab('master')} className={`w-full p-3 rounded ${activeTab === 'master' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}>마스터 데이터 관리</button>
        </nav>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'fcst' ? (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">FCST 스케줄링</h2>
            <textarea className="w-full h-40 p-4 rounded shadow-sm" placeholder="FCST 데이터 입력..."></textarea>
            <button className="bg-blue-600 text-white px-6 py-2 rounded font-bold shadow-lg">자동 배정 시작</button>
          </div>
        ) : (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">마스터 데이터 관리</h2>
            <div className="bg-white p-6 rounded shadow">
              <h3 className="font-bold mb-4 flex items-center"><Database className="mr-2" /> ATM 스케줄 에디터</h3>
              <table className="w-full border text-left">
                <thead className="bg-gray-50"><tr><th className="p-2 border">ID</th><th className="p-2 border">기간</th><th className="p-2 border">Capa</th><th className="p-2 border">삭제</th></tr></thead>
                <tbody>
                  {mappingRules.atmMaster.map(a => (
                    <tr key={a.id}>
                      <td className="p-2 border">{a.id}</td>
                      <td className="p-2 border">{a.start} ~ {a.end}</td>
                      <td className="p-2 border">{a.maxCapa}</td>
                      <td className="p-2 border"><button onClick={() => removeAtmRule(a.id)} className="text-red-500"><Trash2 size={18}/></button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
